// HasChange applies the HasEdge predicate on the "change" edge.
func HasChange() predicate.ChangePIR {
	return predicate.ChangePIR(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ChangeTable, ChangeColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasChangeWith applies the HasEdge predicate on the "change" edge with a given conditions (other predicates).
func HasChangeWith(preds ...predicate.Change) predicate.ChangePIR {
	return predicate.ChangePIR(func(s *sql.Selector) {
		step := newChangeStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasReviewer applies the HasEdge predicate on the "reviewer" edge.
func HasReviewer() predicate.ChangePIR {
	return predicate.ChangePIR(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2M, true, ReviewerTable, ReviewerPrimaryKey...),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasReviewerWith applies the HasEdge predicate on the "reviewer" edge with a given conditions (other predicates).
func HasReviewerWith(preds ...predicate.User) predicate.ChangePIR {
	return predicate.ChangePIR(func(s *sql.Selector) {
		step := newReviewerStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ChangePIR) predicate.ChangePIR {
	return predicate.ChangePIR(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ChangePIR) predicate.ChangePIR {
	return predicate.ChangePIR(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ChangePIR) predicate.ChangePIR {
	return predicate.ChangePIR(sql.NotPredicates(p))
}
